// 게임 상태
let board = ['', '', '', '', '', '', '', '', ''];
let currentPlayer = 'X';
let gameOver = false;

// DOM 요소
const cells = document.querySelectorAll('.cell');
const gameBoard = document.getElementById('game-board');
const turnIndicator = document.getElementById('turn-indicator');
const winnerDisplay = document.getElementById('winner-display');
const winnerText = document.getElementById('winner-text');
const resetButton = document.getElementById('reset-button');

// 승리 조건 (행, 열, 대각선)
const winningCombinations = [
  [0, 1, 2],
  [3, 4, 5],
  [6, 7, 8],
  [0, 3, 6],
  [1, 4, 7],
  [2, 5, 8],
  [0, 4, 8],
  [2, 4, 6],
];

// 셀 클릭 이벤트
cells.forEach((cell) => {
  cell.addEventListener('click', handleCellClick);
});

function handleCellClick(e) {
  if (gameOver) return;

  const index = parseInt(e.target.dataset.index);

  // 이미 채워진 셀이면 무시
  if (board[index] !== '') return;

  // 보드 업데이트
  board[index] = currentPlayer;

  // UI 업데이트
  e.target.textContent = currentPlayer;
  e.target.classList.add('filled');
  e.target.classList.add(currentPlayer.toLowerCase());

  // 게임 상태 확인
  const result = checkGameState();

  if (result === 'win') {
    endGame(`플레이어 ${currentPlayer} 승리!`);
  } else if (result === 'draw') {
    endGame('무승부!');
  } else {
    // 턴 변경
    currentPlayer = currentPlayer === 'X' ? 'O' : 'X';
    updateTurnIndicator();
  }
}

function checkGameState() {
  // 승리 확인
  for (const [a, b, c] of winningCombinations) {
    if (board[a] && board[a] === board[b] && board[a] === board[c]) {
      highlightWinningCells([a, b, c]);
      return 'win';
    }
  }

  // 무승부 확인
  if (board.every((cell) => cell !== '')) {
    return 'draw';
  }

  return null;
}

function highlightWinningCells(indices) {
  indices.forEach((index) => {
    cells[index].classList.add('winner');
  });
}

function endGame(message) {
  gameOver = true;
  turnIndicator.classList.remove('active');
  winnerDisplay.classList.remove('hidden');
  winnerText.textContent = message;
  gameBoard.style.pointerEvents = 'none';
}

function updateTurnIndicator() {
  turnIndicator.classList.add('active');
  turnIndicator.querySelector('.player').textContent = currentPlayer;
}

function resetGame() {
  board = ['', '', '', '', '', '', '', '', ''];
  currentPlayer = 'X';
  gameOver = false;

  cells.forEach((cell) => {
    cell.textContent = '';
    cell.classList.remove('filled', 'x', 'o', 'winner');
  });

  gameBoard.style.pointerEvents = 'auto';
  winnerDisplay.classList.add('hidden');
  updateTurnIndicator();
}

resetButton.addEventListener('click', resetGame);

// 초기 상태
updateTurnIndicator();

