* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
}

.container {
  text-align: center;
  background: white;
  padding: 40px;
  border-radius: 10px;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
}

h1 {
  color: #333;
  margin-bottom: 30px;
  font-size: 2.5em;
}

.info {
  margin-bottom: 30px;
  font-size: 1.1em;
  color: #555;
  height: 40px;
}

#turn-indicator {
  display: none;
}

#turn-indicator.active {
  display: block;
}

#turn-indicator .player {
  font-weight: bold;
  color: #667eea;
  font-size: 1.3em;
}

#winner-display {
  font-size: 1.5em;
  font-weight: bold;
  color: #27ae60;
  animation: slideIn 0.5s ease-out;
}

#winner-display.hidden {
  display: none;
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.game-board {
  display: grid;
  grid-template-columns: repeat(3, 100px);
  grid-gap: 5px;
  margin: 30px auto;
  background: #ddd;
  padding: 5px;
  border-radius: 5px;
}

.cell {
  width: 100px;
  height: 100px;
  background: white;
  border: none;
  border-radius: 5px;
  font-size: 2em;
  font-weight: bold;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #333;
  transition: all 0.2s ease;
  user-select: none;
}

.cell:hover:not(.filled) {
  background: #f0f0f0;
  transform: scale(1.05);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.cell.filled {
  cursor: not-allowed;
}

.cell.x {
  color: #667eea;
}

.cell.o {
  color: #e74c3c;
}

.cell.winner {
  background: #f1c40f;
  box-shadow: 0 0 10px rgba(241, 196, 15, 0.8);
  animation: pulse 0.6s ease-in-out;
}

@keyframes pulse {
  0%, 100% {
    transform: scale(1);
  }
  50% {
    transform: scale(1.1);
  }
}

.reset-button {
  padding: 12px 40px;
  font-size: 1em;
  background: #667eea;
  color: white;
  border: none;
  border-radius: 5px;
  cursor: pointer;
  font-weight: bold;
  transition: all 0.3s ease;
  margin-top: 20px;
}

.reset-button:hover {
  background: #764ba2;
  transform: translateY(-2px);
  box-shadow: 0 5px 15px rgba(102, 126, 234, 0.4);
}

.reset-button:active {
  transform: translateY(0);
}

