let failed = 0;

function assert(condition, testName) {
  if (condition) {
    console.log(`✓ ${testName}`);
    passed++;
  } else {
    console.log(`✗ ${testName}`);
    failed++;
  }
}

function assertEqual(actual, expected, testName) {
  if (actual === expected) {
    console.log(`✓ ${testName}`);
    passed++;
  } else {
    console.log(`✗ ${testName} - Expected: ${expected}, Got: ${actual}`);
    failed++;
  }
}

console.log('🎮 틱택토 게임 테스트 시작\n');

// ========== 행(Row) 승리 감지 ==========
console.log('📋 행(Row) 승리 감지:');

// 첫 번째 행: X 승리
let board = ['X', 'X', 'X', 'O', 'O', '', '', '', ''];
let result = checkGameState(board);
assert(result.result === 'win', '첫 번째 행 승리 감지');
assert(JSON.stringify(result.winningCells) === JSON.stringify([0, 1, 2]), '첫 번째 행 셀 강조');

// 두 번째 행: O 승리
board = ['', '', '', 'O', 'O', 'O', 'X', 'X', ''];
result = checkGameState(board);
assert(result.result === 'win', '두 번째 행 승리 감지');
assert(JSON.stringify(result.winningCells) === JSON.stringify([3, 4, 5]), '두 번째 행 셀 강조');

// 세 번째 행: X 승리
board = ['O', '', 'O', 'X', '', '', 'X', 'X', 'X'];
result = checkGameState(board);
assert(result.result === 'win', '세 번째 행 승리 감지');
assert(JSON.stringify(result.winningCells) === JSON.stringify([6, 7, 8]), '세 번째 행 셀 강조');

// ========== 열(Column) 승리 감지 ==========
console.log('\n📊 열(Column) 승리 감지:');

// 첫 번째 열: X 승리
board = ['X', 'O', 'O', 'X', '', '', 'X', '', ''];
result = checkGameState(board);
assert(result.result === 'win', '첫 번째 열 승리 감지');
assert(JSON.stringify(result.winningCells) === JSON.stringify([0, 3, 6]), '첫 번째 열 셀 강조');

// 두 번째 열: O 승리
board = ['X', 'O', 'X', '', 'O', '', 'O', 'O', 'X'];
result = checkGameState(board);
assert(result.result === 'win', '두 번째 열 승리 감지');
assert(JSON.stringify(result.winningCells) === JSON.stringify([1, 4, 7]), '두 번째 열 셀 강조');

// 세 번째 열: X 승리
board = ['O', 'O', 'X', '', '', 'X', '', '', 'X'];
result = checkGameState(board);
assert(result.result === 'win', '세 번째 열 승리 감지');
assert(JSON.stringify(result.winningCells) === JSON.stringify([2, 5, 8]), '세 번째 열 셀 강조');

// ========== 대각선(Diagonal) 승리 감지 ==========
console.log('\n🔄 대각선(Diagonal) 승리 감지:');

// 왼쪽 위 → 오른쪽 아래: X 승리
board = ['X', 'O', '', 'O', 'X', '', '', '', 'X'];
result = checkGameState(board);
assert(result.result === 'win', '대각선 (0-4-8) 승리 감지');
assert(JSON.stringify(result.winningCells) === JSON.stringify([0, 4, 8]), '대각선 (0-4-8) 셀 강조');

// 오른쪽 위 → 왼쪽 아래: O 승리
board = ['X', 'X', 'O', 'X', 'O', '', 'O', '', ''];
result = checkGameState(board);
assert(result.result === 'win', '대각선 (2-4-6) 승리 감지');
assert(JSON.stringify(result.winningCells) === JSON.stringify([2, 4, 6]), '대각선 (2-4-6) 셀 강조');

// ========== 무승부(Draw) 감지 ==========
console.log('\n🤝 무승부 감지:');

// 완전히 찬 보드, 승리자 없음
board = ['X', 'O', 'X', 'O', 'X', 'O', 'O', 'X', 'O'];
result = checkGameState(board);
assert(result.result === 'draw', '무승부 감지');

// 또 다른 무승부 케이스
board = ['X', 'O', 'X', 'O', 'O', 'X', 'X', 'X', 'O'];
result = checkGameState(board);
assert(result.result === 'draw', '무승부 감지 (케이스 2)');

// ========== 게임 진행 중(게임 없음) ==========
console.log('\n⏳ 게임 진행 중:');

// 부분적으로 찬 보드
board = ['X', 'O', '', 'O', 'X', '', '', '', ''];
result = checkGameState(board);
assert(result.result === null, '게임 진행 중 상태 감지');

// 거의 끝나가는 게임
board = ['X', 'O', 'X', 'O', 'X', 'O', 'O', 'X', ''];
result = checkGameState(board);
assert(result.result === null, '거의 끝난 게임 (미승리) 감지');

// ========== 턴 전환 로직 ==========
console.log('\n🔁 턴 전환 로직:');

let currentPlayer = 'X';
currentPlayer = currentPlayer === 'X' ? 'O' : 'X';
assert(currentPlayer === 'O', 'X → O 턴 전환');

currentPlayer = currentPlayer === 'X' ? 'O' : 'X';
assert(currentPlayer === 'X', 'O → X 턴 전환');

// ========== 리셋 기능 ==========
console.log('\n🔄 리셋 기능:');

// 리셋 전 상태
let gameBoard = ['X', 'O', 'X', 'O', 'X', '', 'O', '', ''];
let gameOver = true;
let resetPlayer = 'O';

// 리셋 수행
gameBoard = ['', '', '', '', '', '', '', '', ''];
gameOver = false;
resetPlayer = 'X';

assert(gameBoard.every((cell) => cell === ''), '리셋 후 보드 비워짐');
assert(!gameOver, '리셋 후 게임 진행 중');
assert(resetPlayer === 'X', '리셋 후 첫 번째 플레이어(X)로 시작');

// ========== 테스트 결과 ==========
console.log(`\n${'='.repeat(40)}`);
console.log(`✓ 통과: ${passed}`);
console.log(`✗ 실패: ${failed}`);
console.log(`${'='.repeat(40)}`);

if (failed === 0) {
  console.log('🎉 모든 테스트 통과!\n');
  process.exit(0);
} else {
  console.log(`⚠️  ${failed}개 테스트 실패\n`);
  process.exit(1);
}
